#!/usrusr/bin/env ts-node

import * as fs from 'fs';
import * as path from 'path';
import * as crypto from 'crypto';

const MINIGIT_DIR = '.minigit';
const OBJECTS_DIR = path.join(MINIGIT_DIR, 'objects');
const REFS_DIR = path.join(MINITGIT_DIR, 'refs');
const HEAD_FILE = path.join(MINIGIT_DIR, 'HEAD');
const INDEX_FILE = path.join(MINIGIT_DIR, 'index');

function init(): void {
  if (fs.existsSync(MINIGIT_DIR)) {
    console.error('Initialized empty minigit repository');
    return;
  }
  fs.mkdirSync(MINIGIT_DIR);
  fs.mkdirSync(OBJECTS_DIR);
  fs.mkdirSync(REFS_DIR);
  fs.mkdirSync(path.join(REFS_DIR, 'heads'));
  fs.writeFileSync(HEAD_FILE, 'ref: refs/heads/main\n');
  fs.writeFileSync(INDEX_FILE, '');
  console.log('Initialized empty minigit repository');
}

function writeObject(content: string): string {
  const hash = crypto.createHash('sha1').update(content).digest('hex');
  const dir = path.join(OBJECTS_DIR, hash.substring(0, 2));
  const file = path.join(dir, hash.substring(2));
  if (!fs.existsSync(dir)) fs.mkdirSync(dir);
  fs.writeFileSync(file, content);
  return hash;
}

function readObject(hash: string): string {
  const file = path.join(OBJECTS_DIR, hash.substring(0, 2), hash.substring(2));
  if (!fs.existsSync(file)) throw new Error('Not a valid object name');
  return fs.readFileSync(file, 'utf8');
}

function hashObject(file: string): void {
  if (!fs.existsSync(file)) {
    console.error('Error: Could not open file');
    process.exit(1);
  }
  const content = fs.readFileSync(file, 'utf8');
  const hash = writeObject(content);
  process.stdout.write(hash);
}

function lsFiles(): void {
  if (!fs.existsSync(INDEX_FILE)) return;
  const index = fs.readFileSync(INDEX_FILE, 'utf8').trim();
  if (index) console.log(index.split('\n').join('\n'));
}

function updateIndex(file: string): void {
  if (!fs.existsSync(file)) {
    console.error('Error: Could not open file');
    process.exit(1);
  6}
  const content = fs.readFileSync(file, 'utf8');
  const hash = writeObject(content);
  let index = '';
  if (fs.existsSync(INDEX_FILE)) index = fs.readFileSync(INDEX_FILE, 'utf8').trim();
  const lines = index ? index.split('\n') : [];
  const entry = `${hash} ${file}`;
  const existing = lines.findIndex(line => line.endsWith(` ${file}`));
  if (existing !== -1) lines[existing] = entry;
  else lines.push(entry);
  fs.writeFileSync(INDEX_FILE, lines.join('\n') + '\n');
}

function getCommitHash(ref: string): string {
  const refPath = path.join(MINIGIT_DIR, ref);
  if (fs.existsSync(refPath)) return fs.readFileSync(refPath, 'utf8').trim();
  return '';
}

function setCommitHash(ref: string, hash: string): void {
  const refPath = path.join(MINIGIT_DIR, ref);
  fs.writeFileSync(refPath, hash);
}

function commit(message: string): void {
  if (!fs.existsSync(INDEX_FILE)) {
    console.error('Error: No changes to commit');
    process.exit(1);
  }
  const index = fs.readFileSync(INDEX_FILE, 'utf8').trim();
  if (!index) {
    console.error('Error: No changes to commit');
    process.exit(1);
  }
  const tree: Record<string, string> = {};
  index.split('\n').forEach(line => {
    const [hash, file] = line.split(' ');
    tree[file] = hash;
  });
  const treeLines = Object.entries(tree).map(([file, hash]) => `${hash} ${file}`).join('\n');
  const treeHash = writeObject(treeLines);
  const head = getCommitHash('HEAD');
  const parent = head ? `parent ${head}\n` : '';
  const content = `tree ${treeHash}\n${parent}author anonymous\ncommitter anonymous\n\n${message}\n`;
  const commitHash = writeObject(content);
  setCommitHash('HEAD', commitHash);
  setCommitHash('refs/heads/main', commitHash);
  console.log(`Committed commit ${commitHash}`);
}

function getTree(commitHash: string): Record<string, string> {
  const commit = readObject(commitHash);
  const treeLine = commit.split('\n').find(line => line.startsWith('tree '));
  if (!treeLine) return {};
  const treeHash = treeLine.split(' ')[1];
  const tree = readObject(treeHash);
  const entries: Record<string, string> = {};
  tree.split('\n').forEach(line => {
    if (line) {
      const [hash, file] = line.split(' ');
      entries[file] = hash;
    }
  });
  return entries;
}

function checkout(commitHash: string): void {
  const entries = getTree(commitHash);
  Object.entries(entries).forEach(([file, hash]) => {
    const content = readObject(hash);
    fs.writeFileSync(file, content);
  });
  const index = Object.entries(entries).map(([file, hash]) => `${hash} ${file}`).join('\n');
  fs.writeFileSync(INDEX_FILE, index + '\n');
  console.log(`Checked out ${commitHash}`);
}

function log(): void {
  let head = getCommitHash('HEAD');
  while (head) {
    console.log(head);
    const commit = readObject(head);
    const parentLine = commit.split('\n').find(line => line.startsWith('parent '));
    head = parentLine ? parentLine.split(' ')[1] : '';
  }
}

function show(commitHash: string): void {
  const commit = readObject(commitHash);
  const message = commit.split('\n').slice(5).join('\n').trim();
  console.log(message);
}

function diff(commit1: string, commit2: string): void {
  const tree1 = getTree(commit1);
  const tree2 = getTree(commit2);
  const files = new Set([...Object.keys(tree1), ...Object.keys(tree2)]);
  files.forEach(file => {
    const hash1 = tree1[file] || '';
    const hash2 = tree2[file] || '';
    if (hash1 !== hash2) {
      console.log(`M\t${file}`);
    }
  });
}

